                    <button class="preset-btn" data-min="1">1 min</button>
                    <button class="preset-btn" data-min="5">5 min</button>
                    <button class="preset-btn" data-min="10">10 min</button>
                    <button class="preset-btn" data-min="25">25 min</button>
                    <button class="preset-btn" data-min="60">1 hour</button>
                    <button class="preset-btn" data-min="90">1.5 hours</button>
                </div>

                <label style="display: block; margin-bottom: 10px; font-size: 0.85rem; color: var(--text-secondary); text-transform: uppercase; letter-spacing: 0.1em;">Or Set Duration</label>
                <div class="duration-grid">
                    <div class="duration-input">
                        <input type="number" id="daysInput" min="0" max="999" value="0" placeholder="00"/>
                        <label>Days</label>
                    </div>
                    <div class="duration-input">
                        <input type="number" id="hoursInput" min="0" max="23" value="0" placeholder="00"/>
                        <label>Hours</label>
                    </div>
                    <div class="duration-input">
                        <input type="number" id="minutesInput" min="0" max="59" value="5" placeholder="00"/>
                        <label>Minutes</label>
                    </div>
                    <div class="duration-input">
                        <input type="number" id="secondsInput" min="0" max="59" value="0" placeholder="00"/>
                        <label>Seconds</label>
                    </div>
                </div>
            </div>

            <!-- Button Group -->
            <div class="button-group">
                <button class="btn btn-primary" id="startBtn">
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
                        <path d="M8 5v14l11-7z"/>
                    </svg>
                    Start
                </button>
                <button class="btn" id="pauseBtn" disabled>
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
                        <path d="M6 19h4V5H6v14zm8-14v14h4V5h-4z"/>
                    </svg>
                    Pause
                </button>
                <button class="btn btn-danger" id="resetBtn">
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
                        <path d="M12 5V1L7 6l5 5V7c3.31 0 6 2.69 6 6s-2.69 6-6 6-6-2.69-6-6H4c0 4.42 3.58 8 8 8s8-3.58 8-8-3.58-8-8-8z"/>
                    </svg>
                    Reset
                </button>
            </div>
        </div>
    </div>

    <!-- Alarm Overlay -->
    <div class="alarm-overlay" id="alarmOverlay">
        <div class="alarm-content">
            <div class="alarm-icon">
                <span id="alarmEmoji">⏰</span>
            </div>
            <div class="alarm-text">TIME'S UP!</div>
            <button class="btn btn-primary" id="dismissAlarm">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                    <path d="M5 13l4 4L19 7"/>
                </svg>
                Dismiss
            </button>
        </div>
    </div>

    <!-- Toast Notification -->
    <div class="toast" id="toast">
        <span class="toast-icon" id="toastIcon"></span>
        <span id="toastMessage"></span>
    </div>

    <script>
        // Timer state
        let timerState = {
            targetTime: null,
            totalDuration: 0,
            remaining: 0,
            isRunning: false,
            isPaused: false,
            intervalId: null,
            audioEnabled: false,
            audioContext: null
        };

        // DOM elements
        const el = {
            days: document.getElementById('days'),
            hours: document.getElementById('hours'),
            minutes: document.getElementById('minutes'),
            seconds: document.getElementById('seconds'),
            dateTimeInput: document.getElementById('dateTimeInput'),
            daysInput: document.getElementById('daysInput'),
            hoursInput: document.getElementById('hoursInput'),
            minutesInput: document.getElementById('minutesInput'),
            secondsInput: document.getElementById('secondsInput'),
            startBtn: document.getElementById('startBtn'),
            pauseBtn: document.getElementById('pauseBtn'),
            resetBtn: document.getElementById('resetBtn'),
            audioStatus: document.getElementById('audioStatus'),
            statusDot: document.getElementById('statusDot'),
            statusText: document.getElementById('statusText'),
            endTime: document.getElementById('endTime'),
            progressRing: document.getElementById('progressRing'),
            alarmOverlay: document.getElementById('alarmOverlay'),
            dismissAlarm: document.getElementById('dismissAlarm'),
            toast: document.getElementById('toast'),
            toastIcon: document.getElementById('toastIcon'),
            toastMessage: document.getElementById('toastMessage')
        };

        // Circle circumference for progress ring
        const CIRCUMFERENCE = 2 * Math.PI * 90; // r = 90

        // Initialize
        function init() {
            // Set default datetime to 5 minutes from now
            const defaultTime = new Date(Date.now() + 5 * 60 * 1000);
            el.dateTimeInput.value = formatDateTimeLocal(defaultTime);
            updateDisplay(5 * 60 * 1000);

            // Event listeners
            el.startBtn.addEventListener('click', startTimer);
            el.pauseBtn.addEventListener('click', pauseTimer);
            el.resetBtn.addEventListener('click', resetTimer);
            el.audioStatus.addEventListener('click', enableAudio);
            el.dismissAlarm.addEventListener('click', dismissAlarm);

            // Preset buttons
            document.querySelectorAll('.preset-btn').forEach(btn => {
                btn.addEventListener('click', () => {
                    const minutes = parseInt(btn.dataset.min);
                    setDurationFromMinutes(minutes);
                });
            });

            // Input synchronization
            el.dateTimeInput.addEventListener('change', syncFromDateTime);
            [el.daysInput, el.hoursInput, el.minutesInput, el.secondsInput].forEach(input => {
                input.addEventListener('change', syncFromDuration);
            });
        }

        // Audio setup - requires user interaction
        function enableAudio() {
            try {
                if (!timerState.audioContext) {
                    timerState.audioContext = new (window.AudioContext || window.webkitAudioContext)();
                }

                if (timerState.audioContext.state === 'suspended') {
                    timerState.audioContext.resume();
                }

                timerState.audioEnabled = true;
                el.audioStatus.classList.add('enabled');
                el.audioStatus.innerHTML = `
                    <svg viewBox="0 0 24 24" fill="currentColor">
                        <path d="M3 9v6h4l5 5V4L7 9H3zm13.5 3c0-1.77-1.02-3.29-2.5-4.03v8.05c1.48-.73 2.5-2.25 2.5-4.02zM14 3.23v2.06c2.89.86 5 3.54 5 6.71s-2.11 5.85-5 6.71v2.06c4.01-.91 7-4.49 7-8.77s-2.99-7.86-7-8.77z"/>
                    </svg>
                    <span>Audio alarm enabled</span>
                `;
                showToast('Audio enabled successfully', 'success');
            } catch (error) {
                showToast('Failed to enable audio', 'error');
            }
        }

        // Play alarm sound using Web Audio API
        function playAlarmSound() {
            if (!timerState.audioEnabled || !timerState.audioContext) return;

            const ctx = timerState.audioContext;
            const now = ctx.currentTime;

            // Create oscillator for beep
            function playBeep(frequency, start, duration) {
                const osc = ctx.createOscillator();
                const gain = ctx.createGain();

                osc.connect(gain);
                gain.connect(ctx.destination);

                osc.type = 'sine';
                osc.frequency.setValueAtTime(frequency, start);

                gain.gain.setValueAtTime(0, start);
                gain.gain.linearRampToValueAtTime(0.3, start + 0.05);
                gain.gain.linearRampToValueAtTime(0, start + duration);

                osc.start(start);
                osc.stop(start + duration);
            }

            // Create alarm pattern: 3 beeps, pause, 3 beeps...
            for (let i = 0; i < 3; i++) {
                const start = now + i * 0.3;
                playBeep(880, start, 0.2);  // A5
                playBeep(1100, start + 0.1, 0.2); // C#6 - harmonic
            }

            // Repeat after 1 second
            setTimeout(() => {
                if (timerState.isRunning && timerState.remaining <= 0) {
                    playAlarmSound();
                }
            }, 1000);
        }

        // Format datetime for input
        function formatDateTimeLocal(date) {
            const year = date.getFullYear();
            const month = String(date.getMonth() + 1).padStart(2, '0');
            const day = String(date.getDate()).padStart(2, '0');
            const hour = String(date.getHours()).padStart(2, '0');
            const minute = String(date.getMinutes()).padStart(2, '0');
            return `${year}-${month}-${day}T${hour}:${minute}`;
        }

        // Set duration from preset minutes
        function setDurationFromMinutes(minutes) {
            const now = Date.now();
            const target = now + minutes * 60 * 1000;
            el.dateTimeInput.value = formatDateTimeLocal(new Date(target));
            syncFromDateTime();
            showToast(`Timer set for ${minutes} minute${minutes > 1 ? 's' : ''}`, 'success');
        }

        // Sync duration inputs from datetime
        function syncFromDateTime() {
            const target = new Date(el.dateTimeInput.value).getTime();
            const now = Date.now();
            const diff = Math.max(0, target - now);

            const days = Math.floor(diff / (1000 * 60 * 60 * 24));
            const hours = Math.floor((diff % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
            const minutes = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
            const seconds = Math.floor((diff % (1000 * 60)) / 1000);

            el.daysInput.value = days;
            el.hoursInput.value = hours;
            el.minutesInput.value = minutes;
            el.secondsInput.value = seconds;

            updateDisplay(diff);
        }

        // Sync datetime from duration inputs
        function syncFromDuration() {
            const days = parseInt(el.daysInput.value) || 0;
            const hours = parseInt(el.hoursInput.value) || 0;
            const minutes = parseInt(el.minutesInput.value) || 0;
            const seconds = parseInt(el.secondsInput.value) || 0;

            const totalMs = ((days * 24 * 60 * 60) + (hours * 60 * 60) + (minutes * 60) + seconds) * 1000;
            const target = Date.now() + totalMs;

            el.dateTimeInput.value = formatDateTimeLocal(new Date(target));
            updateDisplay(totalMs);
        }

        // Start timer
        function startTimer() {
            if (timerState.isRunning) return;

            // Calculate target time
            const days = parseInt(el.daysInput.value) || 0;
            const hours = parseInt(el.hoursInput.value) || 0;
            const minutes = parseInt(el.minutesInput.value) || 0;
            const seconds = parseInt(el.secondsInput.value) || 0;

            const totalMs = ((days * 24 * 60 * 60) + (hours * 60 * 60) + (minutes * 60) + seconds) * 1000;

            if (totalMs <= 0) {
                showToast('Please set a duration greater than 0', 'error');
                return;
            }

            if (!timerState.isPaused) {
                timerState.targetTime = Date.now() + totalMs;
                timerState.totalDuration = totalMs;
            }

            timerState.isRunning = true;
            timerState.isPaused = false;

            // Update UI
            el.startBtn.disabled = true;
            el.pauseBtn.disabled = false;
            el.statusDot.classList.add('running');
            el.statusDot.classList.remove('paused');
            el.statusText.textContent = 'Running';
            el.endTime.textContent = `Ends at ${new Date(timerState.targetTime).toLocaleTimeString()}`;

            // Disable inputs
            toggleInputs(false);

            // Start interval
            timerState.intervalId = setInterval(tick, 100);
            tick(); // Immediate update
        }

        // Pause timer
        function pauseTimer() {
            if (!timerState.isRunning) return;

            timerState.isRunning = false;
            timerState.isPaused = true;
            clearInterval(timerState.intervalId);

            // Calculate new remaining time from now
            timerState.remaining = timerState.targetTime - Date.now();

            // Update UI
            el.startBtn.disabled = false;
            el.pauseBtn.disabled = true;
            el.statusDot.classList.remove('running');
            el.statusDot.classList.add('paused');
            el.statusText.textContent = 'Paused';
        }

        // Reset timer
        function resetTimer() {
            timerState.isRunning = false;
            timerState.isPaused = false;
            timerState.remaining = 0;
            clearInterval(timerState.intervalId);

            // Update UI
            el.startBtn.disabled = false;
            el.pauseBtn.disabled = true;
            el.statusDot.classList.remove('running', 'paused');
            el.statusText.textContent = 'Ready';
            el.endTime.textContent = '';

            // Re-sync display
            syncFromDuration();

            // Enable inputs
            toggleInputs(true);

            // Reset progress ring
            el.progressRing.style.strokeDashoffset = 0;
        }

        // Toggle input enable/disable
        function toggleInputs(enabled) {
            const inputs = [el.dateTimeInput, el.daysInput, el.hoursInput, el.minutesInput, el.secondsInput];
            inputs.forEach(input => input.disabled = !enabled);
        }

        // Timer tick
        function tick() {
            const now = Date.now();
            const remaining = timerState.targetTime - now;

            if (remaining <= 0) {
                timerComplete();
                return;
            }

            timerState.remaining = remaining;
            updateDisplay(remaining);
            updateProgress(remaining);
        }

        // Update display
        function updateDisplay(ms) {
            const days = Math.floor(ms / (1000 * 60 * 60 * 24));
            const hours = Math.floor((ms % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
            const minutes = Math.floor((ms % (1000 * 60 * 60)) / (1000 * 60));
            const seconds = Math.floor((ms % (1000 * 60)) / 1000);

            el.days.textContent = String(days).padStart(2, '0');
            el.hours.textContent = String(hours).padStart(2, '0');
            el.minutes.textContent = String(minutes).padStart(2, '0');
            el.seconds.textContent = String(seconds).padStart(2, '0');
        }

        // Update progress ring
        function updateProgress(remaining) {
            const progress = timerState.totalDuration > 0 ? remaining / timerState.totalDuration : 1;
            const offset = CIRCUMFERENCE * (1 - progress);
            el.progressRing.style.strokeDashoffset = offset;
        }

        // Timer complete
        function timerComplete() {
            timerState.isRunning = false;
            timerState.remaining = 0;
            clearInterval(timerState.intervalId);

            updateDisplay(0);
            el.progressRing.style.strokeDashoffset = CIRCUMFERENCE;

            // Update UI
            el.startBtn.disabled = false;
            el.pauseBtn.disabled = true;
            el.statusDot.classList.remove('running');
            el.statusText.textContent = 'Completed';

            // Enable inputs
            toggleInputs(true);

            // Show alarm
            showAlarm();

            // Play sound
            playAlarmSound();

            // Show notification toast
            showToast('Timer completed!', 'success');
        }

        // Show alarm overlay
        function showAlarm() {
            el.alarmOverlay.classList.add('active');
        }

        // Dismiss alarm
        function dismissAlarm() {
            el.alarmOverlay.classList.remove('active');
            resetTimer();
        }

        // Toast notification
        function showToast(message, type) {
            el.toastIcon.className = 'toast-icon ' + type;
            el.toastIcon.innerHTML = type === 'success' ? '✓' : '✕';
            el.toastMessage.textContent = message;
            el.toast.classList.add('show');

            setTimeout(() => {
                el.toast.classList.remove('show');
            }, 3000);
        }

        // Initialize on load
        init();
    </script>
