            50% { transform: translate(-20px, 20px) scale(0.95); }
            75% { transform: translate(20px, 10px) scale(1.05); }
        }

        /* Header */
        header {
            text-align: center;
            padding: 60px 20px 40px;
            z-index: 1;
        }

        .logo {
            width: 80px;
            height: 80px;
            margin: 0 auto 30px;
            background: linear-gradient(135deg, var(--accent-coral), var(--accent-purple), var(--accent-cyan));
            border-radius: 20px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 2.5rem;
            box-shadow: 0 10px 40px rgba(167, 139, 250, 0.3);
            animation: pulse-glow 3s ease infinite;
        }

        @keyframes pulse-glow {
            0%, 100% { box-shadow: 0 10px 40px rgba(167, 139, 250, 0.3); }
            50% { box-shadow: 0 15px 60px rgba(167, 139, 250, 0.5), 0 0 80px rgba(103, 232, 249, 0.3); }
        }

        header h1 {
            font-size: 3rem;
            font-weight: 300;
            letter-spacing: 0.15em;
            margin-bottom: 15px;
            background: linear-gradient(135deg, var(--accent-coral), var(--accent-purple), var(--accent-cyan));
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
            background-clip: text;
            background-size: 200% 200%;
            animation: shimmer 3s ease infinite;
        }

        @keyframes shimmer {
            0%, 100% { background-position: 0% 50%; }
            50% { background-position: 100% 50%; }
        }

        header p {
            color: var(--text-secondary);
            font-size: 1.1rem;
            max-width: 600px;
            margin: 0 auto;
            line-height: 1.6;
        }

        /* Grid */
        .container {
            max-width: 1200px;
            margin: 0 auto;
            width: 100%;
            z-index: 1;
        }

        .grid {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
            gap: 24px;
            padding: 20px 0 60px;
        }

        /* Cards */
        .card {
            background: var(--glass-bg);
            backdrop-filter: blur(20px);
            -webkit-backdrop-filter: blur(20px);
            border: 1px solid var(--glass-border);
            border-radius: 24px;
            box-shadow: var(--glass-shadow);
            padding: 32px;
            text-decoration: none;
            color: var(--text-primary);
            transition: all 0.4s ease;
            display: flex;
            flex-direction: column;
            align-items: flex-start;
            position: relative;
            overflow: hidden;
        }

        .card::before {
            content: '';
            position: absolute;
            top: 0;
            left: 0;
            right: 0;
            height: 3px;
            background: linear-gradient(90deg, var(--accent-coral), var(--accent-purple), var(--accent-cyan));
            transform: scaleX(0);
            transition: transform 0.4s ease;
        }

        .card:hover {
            transform: translateY(-8px);
            box-shadow: 0 20px 60px rgba(0, 0, 0, 0.5);
            border-color: rgba(255, 255, 255, 0.3);
        }

        .card:hover::before {
            transform: scaleX(1);
        }

        .card-icon {
            width: 60px;
            height: 60px;
            border-radius: 16px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 1.8rem;
            margin-bottom: 24px;
            transition: transform 0.3s ease;
        }

        .card:hover .card-icon {
            transform: scale(1.1);
        }

        .card-icon.memory { background: linear-gradient(135deg, rgba(255, 107, 107, 0.2), rgba(255, 107, 107, 0.1)); }
        .card-icon.economic { background: linear-gradient(135deg, rgba(167, 139, 250, 0.2), rgba(167, 139, 250, 0.1)); }
        .card-icon.contacts { background: linear-gradient(135deg, rgba(103, 232, 249, 0.2), rgba(103, 232, 249, 0.1)); }
        .card-icon.timer { background: linear-gradient(135deg, rgba(255, 107, 107, 0.2), rgba(167, 139, 250, 0.2)); }
        .card-icon.character { background: linear-gradient(135deg, rgba(103, 232, 249, 0.2), rgba(255, 107, 107, 0.2)); }

        .card h2 {
            font-size: 1.5rem;
            font-weight: 500;
            margin-bottom: 12px;
            letter-spacing: 0.02em;
        }

        .card p {
            color: var(--text-secondary);
            font-size: 0.95rem;
            line-height: 1.6;
            flex-grow: 1;
        }

        .card-arrow {
            margin-top: 24px;
            display: flex;
            align-items: center;
            gap: 8px;
            color: var(--text-secondary);
            font-size: 0.9rem;
            transition: all 0.3s ease;
        }

        .card:hover .card-arrow {
            color: var(--accent-cyan);
            transform: translateX(4px);
        }

        .card-arrow svg {
            width: 18px;
            height: 18px;
            transition: transform 0.3s ease;
        }

        .card:hover .card-arrow svg {
            transform: translateX(4px);
        }

        /* Footer */
        footer {
            text-align: center;
            padding: 40px 20px;
            color: var(--text-secondary);
            font-size: 0.9rem;
            z-index: 1;
        }

        footer .version {
            display: inline-flex;
            align-items: center;
            gap: 8px;
            padding: 8px 16px;
            background: var(--glass-bg);
            backdrop-filter: blur(10px);
            border: 1px solid var(--glass-border);
            border-radius: 20px;
            font-size: 0.85rem;
        }

        footer .version-dot {
            width: 8px;
            height: 8px;
            background: var(--accent-cyan);
            border-radius: 50%;
            box-shadow: 0 0 10px var(--accent-cyan);
            animation: pulse-dot 2s ease infinite;
        }

        @keyframes pulse-dot {
            0%, 100% { opacity: 1; }
            50% { opacity: 0.5; }
        }

        footer .subtitle {
            margin-top: 20px;
            opacity: 0.6;
        }

        /* Responsive */
        @media (max-width: 768px) {
            header h1 {
                font-size: 2rem;
            }
            header p {
                font-size: 1rem;
            }
            .grid {
                grid-template-columns: 1fr;
            }
        }

        /* Section titles */
        .section-title {
            font-size: 0.85rem;
            text-transform: uppercase;
            letter-spacing: 0.2em;
            color: var(--text-secondary);
            margin: 40px 0 20px;
            padding-left: 10px;
            border-left: 2px solid var(--accent-purple);
        }
    </style>
